def suma(a, b):
    # Función que retorna la suma de dos números
    return a + b

if __name__ == '__main__':
    # Pruebas unitarias
    try:
        assert suma(2, 3) == 5, "suma(2, 3) no retorna 5"
        assert suma(0, 0) == 0, "suma(0, 0) no retorna 0"
        assert suma(-1, 1) == 0, "suma(-1, 1) no retorna 0"
        assert suma(10, 20) == 30, "suma(10, 20) no retorna 30"
        print("CRITERIO OK")
    except AssertionError as e:
        print(f"CRITERIO FALLO: {e}")
